    /**
     * Buscar iconos por término
     */
    public static function search($term)
    {
        return collect(static::all())->filter(function ($icon) use ($term) {
            return stripos($icon['nombre'], $term) !== false || 
                   stripos($icon['icono'], $term) !== false;
        })->values()->toArray();
    }
    
    /**
     * Obtener icono por nombre de icono
     */
    public static function getByIconName($iconName)
    {
        return collect(static::all())->firstWhere('icono', $iconName);
    }
    
    /**
     * Obtener HTML del icono
     */
    public static function getHtml($iconName, $classes = '')
    {
        $icon = static::getByIconName($iconName);
        
        if (!$icon) {
            return '';
        }
        
        $class = $icon['prefijo'] . ' ' . $icon['prefijo'] . '-' . $icon['icono'];
        
        if (!empty($classes)) {
            $class .= ' ' . $classes;
        }
        
        return '<i class="' . $class . '"></i>';
    }
    
    /**
     * Obtener clases CSS del icono
     */
    public static function getClasses($iconName)
    {
        $icon = static::getByIconName($iconName);
        
        if (!$icon) {
            return '';
        }
        
        return $icon['prefijo'] . ' ' . $icon['prefijo'] . '-' . $icon['icono'];
    }
    
    /**
     * Verificar si un icono existe
     */
    public static function exists($iconName)
    {
        return !is_null(static::getByIconName($iconName));
    }
}